document.addEventListener("DOMContentLoaded",async()=>{const e=document.getElementById("menu-toggle"),t=document.getElementById("nav-links");e.addEventListener("click",()=>{const a=t.classList.toggle("active");e.setAttribute("aria-expanded",String(a))}),document.querySelectorAll(".nav-links a, .floating-rsvp").forEach(a=>{a.addEventListener("click",o=>{o.preventDefault(),t.classList.remove("active"),e.setAttribute("aria-expanded","false");const n=a.getAttribute("href"),c=document.querySelector(n);c&&c.scrollIntoView({behavior:"smooth",block:"start"})})}),window.addEventListener("scroll",()=>{const e=document.querySelector(".navbar");window.scrollY>50?(e.style.background="rgba(247,248,246,0.96)",e.style.boxShadow="0 4px 20px rgba(0,0,0,0.05)"):(e.style.background="rgba(247,248,246,0.90)",e.style.boxShadow="none")});const a=new IntersectionObserver(e=>{e.forEach(e=>{const t=e.target.querySelector("iframe");t&&(e.isIntersecting?t.style.display="block":t.style.display="none")})},{root:null,threshold:.2,rootMargin:"200px 0px"});document.querySelectorAll(".iframe-limit").forEach(e=>a.observe(e));const o=document.querySelectorAll(".map-btn"),n=document.getElementById("ceremony-map"),c=document.getElementById("reception-map");o.forEach(e=>{e.addEventListener("click",()=>{const t=e.dataset.map;o.forEach(e=>e.classList.remove("active")),e.classList.add("active"),n.classList.remove("active-map"),c.classList.remove("active-map"),"ceremony"===t?n.classList.add("active-map"):c.classList.add("active-map")})})});